SELECT ewi.department_id AS departmentId, COUNT(*) AS cnt FROM employee_work_info ewi JOIN employee e ON ewi.employee_id = e.id WHERE e.status IN
#{item}
AND e.is_deleted = 0 GROUP BY ewi.department_id

SELECT e.id, e.employee_no AS employeeNo, epi.name, d.name AS departmentName, p.name AS positionName, ewi.job_level AS jobLevel, e.status, e.hire_date AS hireDate FROM employee e LEFT JOIN employee_personal_info epi ON e.id = epi.employee_id LEFT JOIN employee_work_info ewi ON e.id = ewi.employee_id LEFT JOIN department d ON ewi.department_id = d.id LEFT JOIN position p ON ewi.position_id = p.id WHERE e.is_deleted = 0
AND (epi.name LIKE CONCAT('%', #{keyword}, '%') OR e.employee_no LIKE CONCAT('%', #{keyword}, '%') OR epi.phone LIKE CONCAT('%', #{keyword}, '%'))
AND ewi.department_id IN
#{item}
AND ewi.position_id IN
#{item}
AND e.status IN
#{item}
AND ewi.job_level IN
#{item}
AND e.hire_date >= #{hireDateStart}
AND e.hire_date <= #{hireDateEnd}
AND ewi.department_id IN
#{item}
AND e.id = #{selfEmployeeId}
ORDER BY e.hire_date DESC
